vector<vector<long long>> solve(vector<vector<long long>> grid, long long x, long long y, long long k) {
    // Iterate over each row in the submatrix to be vertically flipped
    for (long long i = 0; i < k / 2; ++i) {
        long long row1 = x + i;
        long long row2 = x + k - 1 - i;
        // Swap the corresponding rows within the submatrix columns
        for (long long j = y; j < y + k; ++j) {
            swap(grid[row1][j], grid[row2][j]);
        }
    }
    return grid;
}
